1	package com.macro.mall.portal.service.impl;
2	
3	import com.macro.mall.model.OmsCartItem;
4	import com.macro.mall.model.PmsProductFullReduction;
5	import com.macro.mall.model.PmsProductLadder;
6	import com.macro.mall.model.PmsSkuStock;
7	import com.macro.mall.portal.dao.PortalProductDao;
8	import com.macro.mall.portal.domain.CartPromotionItem;
9	import com.macro.mall.portal.domain.PromotionProduct;
10	import com.macro.mall.portal.service.OmsPromotionService;
11	import org.springframework.beans.BeanUtils;
12	import org.springframework.beans.factory.annotation.Autowired;
13	import org.springframework.stereotype.Service;
14	
15	import java.math.BigDecimal;
16	import java.math.RoundingMode;
17	import java.util.*;
18	
19	/**
20	 * Created by macro on 2018/8/27.
21	 * 促销管理Service实现类
22	 */
23	@Service
24	public class OmsPromotionServiceImpl implements OmsPromotionService {
25	    @Autowired
26	    private PortalProductDao portalProductDao;
27	
28	    @Override
29	    public List<CartPromotionItem> calcCartPromotion(List<OmsCartItem> cartItemList) {
30	        //1.先根据productId对CartItem进行分组，以spu为单位进行计算优惠
31	        Map<Long, List<OmsCartItem>> productCartMap = groupCartItemBySpu(cartItemList);
32	        //2.查询所有商品的优惠相关信息
33	        List<PromotionProduct> promotionProductList = getPromotionProductList(cartItemList);
34	        //3.根据商品促销类型计算商品促销优惠价格
35	        List<CartPromotionItem> cartPromotionItemList = new ArrayList<>();
36	        for (Map.Entry<Long, List<OmsCartItem>> entry : productCartMap.entrySet()) {
37	            Long productId = entry.getKey();
38	            PromotionProduct promotionProduct = getPromotionProductById(productId, promotionProductList);
39	            List<OmsCartItem> itemList = entry.getValue();
40	            Integer promotionType = promotionProduct.getPromotionType();
41	            if (promotionType == 1) {
42	                //单品促销
43	                for (OmsCartItem item : itemList) {
44	                    CartPromotionItem cartPromotionItem = new CartPromotionItem();
45	                    BeanUtils.copyProperties(item,cartPromotionItem);
46	                    cartPromotionItem.setPromotionMessage("单品促销");
47	                    //商品原价-促销价
48	                    PmsSkuStock skuStock = getOriginalPrice(promotionProduct, item.getProductSkuId());
49	                    BigDecimal originalPrice = skuStock.getPrice();
50	                    //单品促销使用原价
51	                    cartPromotionItem.setPrice(originalPrice);
52	                    cartPromotionItem.setReduceAmount(originalPrice.subtract(skuStock.getPromotionPrice()));
53	                    cartPromotionItem.setRealStock(skuStock.getStock()-skuStock.getLockStock());
54	                    cartPromotionItem.setIntegration(promotionProduct.getGiftPoint());
55	                    cartPromotionItem.setGrowth(promotionProduct.getGiftGrowth());
56	                    cartPromotionItemList.add(cartPromotionItem);
57	                }
58	            } else if (promotionType == 3) {
59	                //打折优惠
60	                int count = getCartItemCount(itemList);
61	                PmsProductLadder ladder = getProductLadder(count, promotionProduct.getProductLadderList());
62	                if(ladder!=null){
63	                    for (OmsCartItem item : itemList) {
64	                        CartPromotionItem cartPromotionItem = new CartPromotionItem();
65	                        BeanUtils.copyProperties(item,cartPromotionItem);
66	                        String message = getLadderPromotionMessage(ladder);
67	                        cartPromotionItem.setPromotionMessage(message);
68	                        //商品原价-折扣*商品原价
69	                        PmsSkuStock skuStock = getOriginalPrice(promotionProduct,item.getProductSkuId());
70	                        BigDecimal originalPrice = skuStock.getPrice();
71	                        BigDecimal reduceAmount = originalPrice.subtract(ladder.getDiscount().multiply(originalPrice));
72	                        cartPromotionItem.setReduceAmount(reduceAmount);
73	                        cartPromotionItem.setRealStock(skuStock.getStock()-skuStock.getLockStock());
74	                        cartPromotionItem.setIntegration(promotionProduct.getGiftPoint());
75	                        cartPromotionItem.setGrowth(promotionProduct.getGiftGrowth());
76	                        cartPromotionItemList.add(cartPromotionItem);
77	                    }
78	                }else{
79	                    handleNoReduce(cartPromotionItemList,itemList,promotionProduct);
80	                }
81	            } else if (promotionType == 4) {
82	                //满减
83	                BigDecimal totalAmount= getCartItemAmount(itemList,promotionProductList);
84	                PmsProductFullReduction fullReduction = getProductFullReduction(totalAmount,promotionProduct.getProductFullReductionList());
85	                if(fullReduction!=null){
86	                    for (OmsCartItem item : itemList) {
87	                        CartPromotionItem cartPromotionItem = new CartPromotionItem();
88	                        BeanUtils.copyProperties(item,cartPromotionItem);
89	                        String message = getFullReductionPromotionMessage(fullReduction);
90	                        cartPromotionItem.setPromotionMessage(message);
91	                        //(商品原价/总价)*满减金额
92	                        PmsSkuStock skuStock= getOriginalPrice(promotionProduct, item.getProductSkuId());
93	                        BigDecimal originalPrice = skuStock.getPrice();
94	                        BigDecimal reduceAmount = originalPrice.divide(totalAmount,RoundingMode.HALF_EVEN).multiply(fullReduction.getReducePrice());
95	                        cartPromotionItem.setReduceAmount(reduceAmount);
96	                        cartPromotionItem.setRealStock(skuStock.getStock()-skuStock.getLockStock());
97	                        cartPromotionItem.setIntegration(promotionProduct.getGiftPoint());
98	                        cartPromotionItem.setGrowth(promotionProduct.getGiftGrowth());
99	                        cartPromotionItemList.add(cartPromotionItem);
100	                    }
101	                }else{
102	                    handleNoReduce(cartPromotionItemList,itemList,promotionProduct);
103	                }
104	            } else {
105	                //无优惠
106	                handleNoReduce(cartPromotionItemList, itemList,promotionProduct);
107	            }
108	        }
109	        return cartPromotionItemList;
110	    }
111	
112	    /**
113	     * 查询所有商品的优惠相关信息
114	     */
115	    private List<PromotionProduct> getPromotionProductList(List<OmsCartItem> cartItemList) {
116	        List<Long> productIdList = new ArrayList<>();
117	        for(OmsCartItem cartItem:cartItemList){
118	            productIdList.add(cartItem.getProductId());
119	        }
120	        return portalProductDao.getPromotionProductList(productIdList);
121	    }
122	
123	    /**
124	     * 以spu为单位对购物车中商品进行分组
125	     */
126	    private Map<Long, List<OmsCartItem>> groupCartItemBySpu(List<OmsCartItem> cartItemList) {
127	        Map<Long, List<OmsCartItem>> productCartMap = new TreeMap<>();
128	        for (OmsCartItem cartItem : cartItemList) {
129	            List<OmsCartItem> productCartItemList = productCartMap.get(cartItem.getProductId());
130	            if (productCartItemList == null) {
131	                productCartItemList = new ArrayList<>();
132	                productCartItemList.add(cartItem);
133	                productCartMap.put(cartItem.getProductId(), productCartItemList);
134	            } else {
135	                productCartItemList.add(cartItem);
136	            }
137	        }
138	        return productCartMap;
139	    }
140	
141	    /**
142	     * 获取满减促销消息
143	     */
144	    private String getFullReductionPromotionMessage(PmsProductFullReduction fullReduction) {
145	        StringBuilder sb = new StringBuilder();
146	        sb.append("满减优惠：");
147	        sb.append("满");
148	        sb.append(fullReduction.getFullPrice());
149	        sb.append("元，");
150	        sb.append("减");
151	        sb.append(fullReduction.getReducePrice());
152	        sb.append("元");
153	        return sb.toString();
154	    }
155	
156	    /**
157	     * 对没满足优惠条件的商品进行处理
158	     */
159	    private void handleNoReduce(List<CartPromotionItem> cartPromotionItemList, List<OmsCartItem> itemList,PromotionProduct promotionProduct) {
160	        for (OmsCartItem item : itemList) {
161	            CartPromotionItem cartPromotionItem = new CartPromotionItem();
162	            BeanUtils.copyProperties(item,cartPromotionItem);
163	            cartPromotionItem.setPromotionMessage("无优惠");
164	            cartPromotionItem.setReduceAmount(new BigDecimal(0));
165	            PmsSkuStock skuStock = getOriginalPrice(promotionProduct,item.getProductSkuId());
166	            if(skuStock!=null){
167	                cartPromotionItem.setRealStock(skuStock.getStock()-skuStock.getLockStock());
168	            }
169	            cartPromotionItem.setIntegration(promotionProduct.getGiftPoint());
170	            cartPromotionItem.setGrowth(promotionProduct.getGiftGrowth());
171	            cartPromotionItemList.add(cartPromotionItem);
172	        }
173	    }
174	
175	    private PmsProductFullReduction getProductFullReduction(BigDecimal totalAmount,List<PmsProductFullReduction> fullReductionList) {
176	        //按条件从高到低排序
177	        fullReductionList.sort(new Comparator<PmsProductFullReduction>() {
178	            @Override
179	            public int compare(PmsProductFullReduction o1, PmsProductFullReduction o2) {
180	                return o2.getFullPrice().subtract(o1.getFullPrice()).intValue();
181	            }
182	        });
183	        for(PmsProductFullReduction fullReduction:fullReductionList){
184	            if(totalAmount.subtract(fullReduction.getFullPrice()).intValue()>=0){
185	                return fullReduction;
186	            }
187	        }
188	        return null;
189	    }
190	
191	    /**
192	     * 获取打折优惠的促销信息
193	     */
194	    private String getLadderPromotionMessage(PmsProductLadder ladder) {
195	        StringBuilder sb = new StringBuilder();
196	        sb.append("打折优惠：");
197	        sb.append("满");
198	        sb.append(ladder.getCount());
199	        sb.append("件，");
200	        sb.append("打");
201	        sb.append(ladder.getDiscount().multiply(new BigDecimal(10)));
202	        sb.append("折");
203	        return sb.toString();
204	    }
205	
206	    /**
207	     * 根据购买商品数量获取满足条件的打折优惠策略
208	     */
209	    private PmsProductLadder getProductLadder(int count, List<PmsProductLadder> productLadderList) {
210	        //按数量从大到小排序
211	        productLadderList.sort(new Comparator<PmsProductLadder>() {
212	            @Override
213	            public int compare(PmsProductLadder o1, PmsProductLadder o2) {
214	                return o2.getCount() - o1.getCount();
215	            }
216	        });
217	        for (PmsProductLadder productLadder : productLadderList) {
218	            if (count >= productLadder.getCount()) {
219	                return productLadder;
220	            }
221	        }
222	        return null;
223	    }
224	
225	    /**
226	     * 获取购物车中指定商品的数量
227	     */
228	    private int getCartItemCount(List<OmsCartItem> itemList) {
229	        int count = 0;
230	        for (OmsCartItem item : itemList) {
231	            count += item.getQuantity();
232	        }
233	        return count;
234	    }
235	
236	    /**
237	     * 获取购物车中指定商品的总价
238	     */
239	    private BigDecimal getCartItemAmount(List<OmsCartItem> itemList, List<PromotionProduct> promotionProductList) {
240	        BigDecimal amount = new BigDecimal(0);
241	        for (OmsCartItem item : itemList) {
242	            //计算出商品原价
243	            PromotionProduct promotionProduct = getPromotionProductById(item.getProductId(), promotionProductList);
244	            PmsSkuStock skuStock = getOriginalPrice(promotionProduct,item.getProductSkuId());
245	            amount = amount.add(skuStock.getPrice().multiply(new BigDecimal(item.getQuantity())));
246	        }
247	        return amount;
248	    }
249	
250	    /**
251	     * 获取商品的原价
252	     */
253	    private PmsSkuStock getOriginalPrice(PromotionProduct promotionProduct, Long productSkuId) {
254	        for (PmsSkuStock skuStock : promotionProduct.getSkuStockList()) {
255	            if (productSkuId.equals(skuStock.getId())) {
256	                return skuStock;
257	            }
258	        }
259	        return null;
260	    }
261	
262	    /**
263	     * 根据商品id获取商品的促销信息
264	     */
265	    private PromotionProduct getPromotionProductById(Long productId, List<PromotionProduct> promotionProductList) {
266	        for (PromotionProduct promotionProduct : promotionProductList) {
267	            if (productId.equals(promotionProduct.getId())) {
268	                return promotionProduct;
269	            }
270	        }
271	        return null;
272	    }
273	}
