    // login 内部：loadUserByUsername → passwordEncoder.matches 返回 false → Asserts.fail 抛出异常
    assertThrows(Exception.class, () -> adminService.login("testuser", "wrongPwd"),
            "密码错误应触发 Asserts.fail 异常");
}

