package com.macro.mall.dao;

import com.macro.mall.model.UmsResource;
import com.macro.mall.model.UmsRole;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.jdbc.AutoConfigureTestDatabase;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * DAO 层集成测试 — 用户角色-资源关系查询。
 *
 * 集成范围：UmsAdminRoleRelationDao → MyBatis → MySQL (Docker)
 * 数据来源：mall.sql 种子数据（admin 用户有角色分配，角色有资源关联）
 *
 * 集成测试关注点：
 *   - SQL 是否正确执行（语法、参数绑定）
 *   - 表关联是否正确（LEFT JOIN、GROUP BY）
 *   - 种子数据是否返回预期结果
 */
@SpringBootTest
@AutoConfigureTestDatabase(replace = AutoConfigureTestDatabase.Replace.NONE)
@ActiveProfiles("dev")
@Transactional
public class UmsAdminRoleRelationDaoIT {

    @Autowired
    private UmsAdminRoleRelationDao adminRoleRelationDao;

    /* 管理员 admin（id=1 或 id=2）在种子数据中有角色和资源分配 */

    @Test
    @DisplayName("集成测试: getRoleList — 查询用户的角色列表")
    void testGetRoleList() {
        // admin 用户 id 在种子数据中已配置角色关联
        // 使用实际 admin id（种子数据中第一个 admin 的 id）
        Long adminId = 1L;

        List<UmsRole> roles = adminRoleRelationDao.getRoleList(adminId);

        assertNotNull(roles, "角色列表不应为 null");
        // admin 至少有一个角色
        if (!roles.isEmpty()) {
            UmsRole role = roles.get(0);
            assertNotNull(role.getName(), "角色应有名称");
        }
    }

    @Test
    @DisplayName("集成测试: getResourceList — 查询用户可访问的资源")
    void testGetResourceList() {
        Long adminId = 1L;

        List<UmsResource> resources = adminRoleRelationDao.getResourceList(adminId);

        assertNotNull(resources, "资源列表不应为 null");
        // admin 用户有资源权限
        if (!resources.isEmpty()) {
            UmsResource resource = resources.get(0);
            assertNotNull(resource.getName(), "资源应有名称");
            assertNotNull(resource.getUrl(), "资源应有 URL");
        }
    }

    @Test
    @DisplayName("集成测试: getResourceList — 不存在的用户返回空列表")
    void testGetResourceListForNonExistentUser() {
        List<UmsResource> resources = adminRoleRelationDao.getResourceList(99999L);
        assertNotNull(resources, "不存在的用户应返回空列表而非 null");
        assertTrue(resources.isEmpty(), "不存在的用户资源列表应为空");
    }

    @Test
    @DisplayName("集成测试: getAdminIdList — 根据资源 ID 反查管理员")
    void testGetAdminIdList() {
        // 使用一个存在的 resource id（种子数据中有资源记录）
        Long resourceId = 1L;

        List<Long> adminIds = adminRoleRelationDao.getAdminIdList(resourceId);

        assertNotNull(adminIds, "管理员 ID 列表不应为 null");
        // 可能有结果也可能无结果，取决于种子数据
    }
}

package com.macro.mall.dao;

import com.macro.mall.dto.OmsOrderQueryParam;
import com.macro.mall.model.OmsOrder;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.jdbc.AutoConfigureTestDatabase;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * DAO 层集成测试 — 订单查询。
 *
 * 集成范围：OmsOrderDao → MyBatis → MySQL (Docker)
 * 数据来源：mall.sql 种子数据（包含订单测试数据）
 *
 * 集成测试关注点：
 *   - SQL 动态条件拼接是否正确
 *   - delete_status=0 过滤是否生效
 *   - 分页查询（PageHelper）是否正常工作
 */
@SpringBootTest
@AutoConfigureTestDatabase(replace = AutoConfigureTestDatabase.Replace.NONE)
@ActiveProfiles("dev")
@Transactional
public class OmsOrderDaoIT {

    @Autowired
    private OmsOrderDao orderDao;

    @Test
    @DisplayName("集成测试: getList — 无条件查询订单列表")
    void testGetOrderListAll() {
        OmsOrderQueryParam param = new OmsOrderQueryParam();
        com.github.pagehelper.PageHelper.startPage(1, 5);

        List<OmsOrder> orders = orderDao.getList(param);

        assertNotNull(orders, "订单列表不应为 null");
        // 验证返回的订单都满足 delete_status=0
        for (OmsOrder order : orders) {
            assertEquals(0, order.getDeleteStatus(),
                    "查询结果应只包含 delete_status=0 的订单");
        }
    }

    @Test
    @DisplayName("集成测试: getList — 按订单状态筛选")
    void testGetOrderListFilterByStatus() {
        OmsOrderQueryParam param = new OmsOrderQueryParam();
        param.setStatus(0); // 待付款状态

        List<OmsOrder> orders = orderDao.getList(param);

        assertNotNull(orders);
        for (OmsOrder order : orders) {
            assertEquals(0, order.getStatus(),
                    "按 status=0 筛选的结果中所有订单 status 应为 0");
        }
    }

    @Test
    @DisplayName("集成测试: getList — 按订单号搜索")
    void testGetOrderListFilterByOrderSn() {
        OmsOrderQueryParam param = new OmsOrderQueryParam();
        param.setOrderSn("2022"); // 搜索包含 "2022" 的订单号

        List<OmsOrder> orders = orderDao.getList(param);

        assertNotNull(orders);
        // 如果有结果，验证订单号包含搜索关键字
        for (OmsOrder order : orders) {
            assertTrue(order.getOrderSn().contains("2022"),
                    "搜索 '2022' 的结果中订单号应包含 '2022'");
        }
    }

    @Test
    @DisplayName("集成测试: getList — 不存在的订单号返回空列表")
    void testGetOrderListWithNonExistentOrderSn() {
        OmsOrderQueryParam param = new OmsOrderQueryParam();
        param.setOrderSn("NONEXISTENT_ORDER_12345");

        List<OmsOrder> orders = orderDao.getList(param);

        assertNotNull(orders);
        assertTrue(orders.isEmpty(), "不存在的订单号应返回空列表");
    }
}

package com.macro.mall.service;

import com.macro.mall.dto.UmsAdminParam;
import com.macro.mall.model.UmsAdmin;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.MethodOrderer;
import org.junit.jupiter.api.Order;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.TestMethodOrder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.jdbc.AutoConfigureTestDatabase;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Service 层集成测试 — 用户认证与注册。
 *
 * 集成范围：UmsAdminService → Mapper → MySQL + Redis (Docker)
 * 测试真实的数据访问和事务行为。
 *
 * 集成测试关注点：
 *   - 注册 → 持久化到 MySQL → 查询返回正确数据
 *   - 登录 → 密码校验 → JWT 生成（真实 token）
 *   - 缓存：getAdminByUsername 先从缓存取再查 DB
 */
@SpringBootTest
@AutoConfigureTestDatabase(replace = AutoConfigureTestDatabase.Replace.NONE)
@ActiveProfiles("dev")
@TestMethodOrder(MethodOrderer.OrderAnnotation.class)
public class UmsAdminServiceIT {

    @Autowired
    private UmsAdminService adminService;

    /* 种子数据中已存在的管理员 */
    private static final String EXISTING_USER = "admin";
    private static final String EXISTING_PASSWORD = "macro123";

    @Test
    @Order(1)
    @DisplayName("集成测试: 查询已存在的管理员 — 验证种子数据")
    void testGetExistingAdmin() {
        UmsAdmin admin = adminService.getAdminByUsername(EXISTING_USER);
        assertNotNull(admin, "种子数据中的 'admin' 用户应存在");
        assertEquals(EXISTING_USER, admin.getUsername());
        assertNotNull(admin.getPassword(), "密码不应为空（BCrypt 编码）");
    }

    @Test
    @Order(2)
    @DisplayName("集成测试: 登录已存在的管理员 — 验证真实 JWT 生成")
    void testLoginWithValidCredentials() {
        String token = adminService.login(EXISTING_USER, EXISTING_PASSWORD);
        assertNotNull(token, "有效凭证登录应返回 token");
        assertTrue(token.length() > 20, "JWT token 应有足够长度");
        // token 应包含三段（header.payload.signature）
        assertTrue(token.contains("."), "JWT token 应包含 '.' 分隔符");
    }

    @Test
    @Order(3)
    @DisplayName("集成测试: 登录失败 — 错误密码")
    void testLoginWithWrongPassword() {
        assertThrows(Exception.class,
                () -> adminService.login(EXISTING_USER, "wrong_password_12345"),
                "错误密码应抛出异常");
    }

    @Test
    @Order(4)
    @DisplayName("集成测试: 注册新用户 → 查询验证 → 持久化成功")
    @Transactional
    void testRegisterAndVerifyPersistence() {
        UmsAdminParam param = new UmsAdminParam();
        param.setUsername("integration_test_user_" + System.currentTimeMillis());
        param.setPassword("testPassword123");
        param.setNickName("集成测试用户");

        UmsAdmin registered = adminService.register(param);
        assertNotNull(registered, "注册应返回非 null 的 UmsAdmin");
        assertNotNull(registered.getId(), "注册后应有自增 ID");

        // 验证持久化：直接从 DB 查询
        UmsAdmin fromDb = adminService.getAdminByUsername(param.getUsername());
        assertNotNull(fromDb, "注册后应能从数据库查询到");
        assertEquals(param.getUsername(), fromDb.getUsername());
        // 密码应为 BCrypt 编码（不以明文存储）
        assertNotEquals(param.getPassword(), fromDb.getPassword(),
                "密码应被 BCrypt 加密存储");
    }
}

