package com.macro.mall.controller;

import com.fasterxml.jackson.databind.ObjectMapper;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.jdbc.AutoConfigureTestDatabase;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.test.web.servlet.MockMvc;

import java.util.HashMap;
import java.util.Map;

import static org.hamcrest.Matchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Controller 层集成测试 — JSON API 端点验证。
 *
 * 集成范围：Spring MVC → UmsAdminController → Service → Mapper → MySQL
 * 使用 MockMvc 模拟 HTTP 请求，与真实 Spring 容器和数据库交互。
 *
 * 集成测试关注点：
 *   - HTTP 状态码
 *   - JSON 响应结构（code、message、data 字段）
 *   - 认证头处理
 *   - 请求参数绑定
 */
@SpringBootTest
@AutoConfigureMockMvc
@AutoConfigureTestDatabase(replace = AutoConfigureTestDatabase.Replace.NONE)
@ActiveProfiles("dev")
public class AdminControllerIT {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    private static final String EXISTING_USER = "admin";
    private static final String EXISTING_PASSWORD = "macro123";

    // ================================================================
    //  5.3  集成测试 — 登录接口 POST /admin/login
    // ================================================================

    @Nested
    @DisplayName("登录接口 POST /admin/login")
    class LoginEndpointTests {

        @Test
        @DisplayName("有效凭证 → 200 + token")
        void testLoginSuccess() throws Exception {
            Map<String, String> body = new HashMap<>();
            body.put("username", EXISTING_USER);
            body.put("password", EXISTING_PASSWORD);

            mockMvc.perform(post("/admin/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(body)))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code", is(200)))
                    .andExpect(jsonPath("$.message", is("操作成功")))
                    .andExpect(jsonPath("$.data.tokenHead", is("Bearer ")))
                    .andExpect(jsonPath("$.data.token", notNullValue()))
                    .andExpect(jsonPath("$.data.token", not(emptyString())));
        }

        @Test
        @DisplayName("错误密码 → 200 + 异常消息（code 非 200）")
        void testLoginWithWrongPassword() throws Exception {
            Map<String, String> body = new HashMap<>();
            body.put("username", EXISTING_USER);
            body.put("password", "wrong_password");

            mockMvc.perform(post("/admin/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(body)))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code", not(200)))
                    .andExpect(jsonPath("$.message", containsString("密码")));
        }

        @Test
        @DisplayName("空请求体 → 400 Bad Request（参数绑定失败）")
        void testLoginWithEmptyBody() throws Exception {
            mockMvc.perform(post("/admin/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content("{}"))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code", not(200)));
        }
    }

    // ================================================================
    //  5.3  集成测试 — 受保护接口 GET /admin/info（需 token）
    // ================================================================

    @Nested
    @DisplayName("受保护接口 GET /admin/info")
    class ProtectedEndpointTests {

        @Test
        @DisplayName("带有效 token → 200 + 返回用户信息")
        void testGetAdminInfoWithValidToken() throws Exception {
            // 先登录获取 token
            Map<String, String> loginBody = new HashMap<>();
            loginBody.put("username", EXISTING_USER);
            loginBody.put("password", EXISTING_PASSWORD);

            String response = mockMvc.perform(post("/admin/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(loginBody)))
                    .andReturn().getResponse().getContentAsString();

            String token = objectMapper.readTree(response)
                    .get("data").get("token").asText();

            // 使用 token 访问受保护接口
            mockMvc.perform(get("/admin/info")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code", is(200)))
                    .andExpect(jsonPath("$.data.username", is(EXISTING_USER)))
                    .andExpect(jsonPath("$.data.menus", notNullValue()))
                    .andExpect(jsonPath("$.data.roles", notNullValue()));
        }

        @Test
        @DisplayName("无 token → 401 或 403（Security 拦截）")
        void testGetAdminInfoWithoutToken() throws Exception {
            mockMvc.perform(get("/admin/info"))
                    .andExpect(status().is4xxClientError());
        }

        @Test
        @DisplayName("无效 token → 401（Security 拦截）")
        void testGetAdminInfoWithInvalidToken() throws Exception {
            mockMvc.perform(get("/admin/info")
                            .header("Authorization", "Bearer invalid.jwt.token.here"))
                    .andExpect(status().is4xxClientError());
        }
    }

    // ================================================================
    //  5.3  集成测试 — 品牌列表 GET /brand/listAll（无需认证）
    // ================================================================

    @Nested
    @DisplayName("公开接口 GET /brand/listAll")
    class PublicEndpointTests {

        @Test
        @DisplayName("无需认证 → 200 + 返回品牌列表")
        void testBrandListAllWithoutAuth() throws Exception {
            mockMvc.perform(get("/brand/listAll"))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.code", is(200)))
                    .andExpect(jsonPath("$.data", notNullValue()));
        }
    }
}

package com.macro.mall.portal.service.impl;

import com.macro.mall.model.UmsMember;
import com.macro.mall.portal.service.OmsCartItemService;
import com.macro.mall.portal.service.UmsMemberCouponService;
import com.macro.mall.portal.service.UmsMemberReceiveAddressService;
import com.macro.mall.portal.service.UmsMemberService;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.ArrayList;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

/**
 * OmsPortalOrderServiceImpl Mock 深度隔离测试。
 *
 * 本测试展示如何使用 Mockito 在完全隔离的环境中对复杂业务逻辑进行测试。
 * OmsPortalOrderServiceImpl 是整个项目中依赖最多的类（9 个 @Autowired），
 * 无法在单元测试（无 Spring 容器）中直接实例化。
 *
 * 通过 Mock 技术：
 *   - 将 7 个外部依赖全部 mock 掉
 *   - 验证订单生成流程中各依赖的交互（verify）
 *   - 验证特定条件下的方法行为（when → then）
 *
 * Mock 技巧展示：
 *   - @Mock 注入多个依赖
 *   - @InjectMocks 自动组装
 *   - when/verify 验证交互模式
 *   - 异常场景的 Mock 模拟
 */
@ExtendWith(MockitoExtension.class)
public class OmsPortalOrderServiceImplMockTest {

    @Mock private UmsMemberService memberService;
    @Mock private OmsCartItemService cartItemService;
    @Mock private UmsMemberReceiveAddressService memberReceiveAddressService;
    @Mock private UmsMemberCouponService memberCouponService;

    @InjectMocks
    private OmsPortalOrderServiceImpl orderService;

    @BeforeEach
    public void setUp() {
        // Mock: 获取当前用户
        UmsMember member = new UmsMember();
        member.setId(1L);
        member.setUsername("test_member");
        lenient().when(memberService.getCurrentMember()).thenReturn(member);
    }

    // ================================================================
    //  5.1  校验场景 Mock 测试
    // ================================================================

    @Nested
    @DisplayName("Mock: 订单确认 — 空购物车场景")
    class ConfirmOrderTests {

        @Test
        @DisplayName("购物车为空 → cartItemService 返回空列表")
        void testGenerateConfirmOrderWithEmptyCart() {
            // Mock: 购物车服务返回空列表
            when(cartItemService.listPromotion(anyLong(), anyList()))
                    .thenReturn(new ArrayList<>());
            // Mock: 收货地址列表为空
            when(memberReceiveAddressService.list())
                    .thenReturn(new ArrayList<>());
            // Mock: 优惠券列表为空
            when(memberCouponService.listCart(anyList(), eq(1)))
                    .thenReturn(new ArrayList<>());

            // 调用被测方法
            com.macro.mall.portal.domain.ConfirmOrderResult result =
                    orderService.generateConfirmOrder(new ArrayList<>());

            assertNotNull(result, "确认订单结果不应为 null");
            assertNotNull(result.getCartPromotionItemList(), "购物车列表不应为 null");
            assertTrue(result.getCartPromotionItemList().isEmpty(), "空购物车应返回空列表");
            assertNotNull(result.getCalcAmount(), "金额计算不应为 null");

            // 验证交互：确认各依赖都被正确调用
            verify(memberService).getCurrentMember();
            verify(cartItemService).listPromotion(anyLong(), anyList());
            verify(memberReceiveAddressService).list();
            verify(memberCouponService).listCart(anyList(), eq(1));
        }
    }

    // ================================================================
    //  5.1  异常场景 Mock 测试
    // ================================================================

    @Nested
    @DisplayName("Mock: 订单生成 — 参数校验失败")
    class GenerateOrderValidationTests {

        @Test
        @DisplayName("未选择收货地址 → Asserts.fail 抛出异常")
        void testGenerateOrderWithoutAddress() {
            com.macro.mall.portal.domain.OrderParam param =
                    new com.macro.mall.portal.domain.OrderParam();
            // memberReceiveAddressId 为 null → 应触发校验失败
            param.setMemberReceiveAddressId(null);

            assertThrows(Exception.class, () -> orderService.generateOrder(param),
                    "未选择收货地址应抛出异常");
        }

        @Test
        @DisplayName("无购物车商品 → Asserts.fail 抛出异常")
        void testGenerateOrderWithoutCartItems() {
            com.macro.mall.portal.domain.OrderParam param =
                    new com.macro.mall.portal.domain.OrderParam();
            param.setMemberReceiveAddressId(1L);
            param.setCartIds(new ArrayList<>()); // 空购物车 ID 列表

            assertThrows(Exception.class, () -> orderService.generateOrder(param),
                    "空购物车应抛出异常");
        }
    }
}

