package com.macro.mall.security;

import com.macro.mall.security.component.JwtAuthenticationTokenFilter;
import com.macro.mall.security.util.JwtTokenUtil;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;

import javax.servlet.FilterChain;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

/**
 * JwtAuthenticationTokenFilter Mock 隔离测试。
 *
 * 测试 Spring Security 过滤链中的 JWT 认证过滤器行为：
 *   - 无 Authorization header → 跳过认证，继续过滤链
 *   - 有合法 token → 从 UserDetailsService 加载用户并设置 SecurityContext
 *   - 有非法 token → 跳过认证（SecurityContext 不设置）
 *
 * 采用 Mock 技术：Mock HttpServletRequest/Response/FilterChain + UserDetailsService，
 * 完全隔离 Spring 容器，验证过滤器的"交互行为"而非集成效果。
 *
 * Mock 技巧展示：
 *   - @Mock: 创建模拟对象
 *   - @InjectMocks: 自动将 mock 注入被测对象
 *   - verify(): 验证方法是否被调用/未调用（行为验证）
 *   - doNothing().when(): 跳过 void 方法
 */
@ExtendWith(MockitoExtension.class)
public class JwtAuthenticationTokenFilterTest {

    @Mock private JwtTokenUtil jwtTokenUtil;
    @Mock private UserDetailsService userDetailsService;
    @Mock private FilterChain filterChain;

    @InjectMocks
    private JwtAuthenticationTokenFilter filter;

    /* 清理 SecurityContext，避免测试间干扰 */
    @BeforeEach
    public void setUp() {
        SecurityContextHolder.clearContext();
    }

    // ================================================================
    //  5.1  Mock 验证 — 请求行为模拟
    // ================================================================

    @Nested
    @DisplayName("Mock: JWT Filter 请求拦截行为")
    class FilterInterceptionTests {

        @Test
        @DisplayName("无 Authorization header → 不加载用户，直接放行")
        void testFilterWithoutAuthHeader() throws Exception {
            MockHttpServletRequest request = new MockHttpServletRequest();
            MockHttpServletResponse response = new MockHttpServletResponse();

            // 无 Authorization header → filter 应直接调用 chain.doFilter
            filter.doFilter(request, response, filterChain);

            // 验证：UserDetailsService 未被调用（因为根本没有 token）
            verify(userDetailsService, never()).loadUserByUsername(anyString());
            // 验证：过滤链继续执行
            verify(filterChain).doFilter(request, response);
            // 验证：SecurityContext 中无认证信息
            assertNull(SecurityContextHolder.getContext().getAuthentication(),
                    "无 token 时不应设置 Authentication");
        }

        @Test
        @DisplayName("Authorization header 不含 Bearer 前缀 → 跳过认证")
        void testFilterWithNonBearerHeader() throws Exception {
            MockHttpServletRequest request = new MockHttpServletRequest();
            request.addHeader("Authorization", "Basic YWRtaW46MTIzNDU2");
            MockHttpServletResponse response = new MockHttpServletResponse();

            filter.doFilter(request, response, filterChain);

            verify(jwtTokenUtil, never()).getUserNameFromToken(anyString());
            verify(filterChain).doFilter(request, response);
        }
    }

    @Nested
    @DisplayName("Mock: JWT Token 验证 — 合法/非法/过期场景")
    class TokenValidationTests {

        @Test
        @DisplayName("合法 token → 加载用户并设置 SecurityContext")
        void testFilterWithValidToken() throws Exception {
            MockHttpServletRequest request = new MockHttpServletRequest();
            request.addHeader("Authorization", "Bearer valid.jwt.token");
            MockHttpServletResponse response = new MockHttpServletResponse();

            // Mock: JWT 解析返回用户名
            when(jwtTokenUtil.getUserNameFromToken("valid.jwt.token")).thenReturn("testuser");
            // Mock: UserDetailsService 返回一个有效用户
            UserDetails mockUser = mock(UserDetails.class);
            when(mockUser.getUsername()).thenReturn("testuser");
            when(mockUser.getAuthorities()).thenReturn(new java.util.ArrayList<>());
            when(userDetailsService.loadUserByUsername("testuser")).thenReturn(mockUser);
            // Mock: token 校验通过
            when(jwtTokenUtil.validateToken(eq("valid.jwt.token"), any(UserDetails.class))).thenReturn(true);

            filter.doFilter(request, response, filterChain);

            // 验证：UserDetailsService 被调用
            verify(userDetailsService).loadUserByUsername("testuser");
            // 验证：token 校验被调用
            verify(jwtTokenUtil).validateToken(eq("valid.jwt.token"), any(UserDetails.class));
            // 验证：SecurityContext 中已设置认证信息
            assertNotNull(SecurityContextHolder.getContext().getAuthentication(),
                    "合法 token 应设置 Authentication");
            assertEquals("testuser",
                    SecurityContextHolder.getContext().getAuthentication().getName());
            // 验证：过滤链继续
            verify(filterChain).doFilter(request, response);
        }

        @Test
        @DisplayName("token 校验失败 → 跳过认证，不设置 SecurityContext")
        void testFilterWithInvalidToken() throws Exception {
            MockHttpServletRequest request = new MockHttpServletRequest();
            request.addHeader("Authorization", "Bearer invalid.token");
            MockHttpServletResponse response = new MockHttpServletResponse();

            when(jwtTokenUtil.getUserNameFromToken("invalid.token")).thenReturn("testuser");
            UserDetails mockUser = mock(UserDetails.class);
            when(userDetailsService.loadUserByUsername("testuser")).thenReturn(mockUser);
            // token 校验返回 false
            when(jwtTokenUtil.validateToken(eq("invalid.token"), any(UserDetails.class))).thenReturn(false);

            filter.doFilter(request, response, filterChain);

            // 虽然加载了用户，但 token 校验失败 → Authentication 不设置
            assertNull(SecurityContextHolder.getContext().getAuthentication(),
                    "token 校验失败不应设置 Authentication");
        }

        @Test
        @DisplayName("token 解析失败（返回 null username）→ 跳过认证")
        void testFilterWithUnparseableToken() throws Exception {
            MockHttpServletRequest request = new MockHttpServletRequest();
            request.addHeader("Authorization", "Bearer garbage.token");
            MockHttpServletResponse response = new MockHttpServletResponse();

            when(jwtTokenUtil.getUserNameFromToken("garbage.token")).thenReturn(null);

            filter.doFilter(request, response, filterChain);

            // 解析失败 → 不调用 UserDetailsService
            verify(userDetailsService, never()).loadUserByUsername(anyString());
            verify(filterChain).doFilter(request, response);
        }
    }

    // ================================================================
    //  5.2  Mock 验证 — verify() 行为断言
    // ================================================================

    @Test
    @DisplayName("验证: 无 Authorization header 时 filter 调用 chain.doFilter 放行")
    void testFilterAlwaysProceedsChain() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest();
        MockHttpServletResponse response = new MockHttpServletResponse();

        // 无 Authorization header → 不应尝试解析 token
        filter.doFilter(request, response, filterChain);

        // 验证：UserDetailsService 未被调用（因为无 token）
        verify(userDetailsService, never()).loadUserByUsername(anyString());
        // 验证：请求继续传递（由后续 FilterSecurityInterceptor 决定是否能访问）
        verify(filterChain, times(1)).doFilter(any(javax.servlet.http.HttpServletRequest.class),
                any(javax.servlet.http.HttpServletResponse.class));
    }
}

