    void testEmptyCartConfirmOrder() {
        when(cartItemService.listPromotion(anyLong(), anyList())).thenReturn(new ArrayList<>());
        when(memberReceiveAddressService.list()).thenReturn(new ArrayList<>());
        when(memberCouponService.listCart(anyList(), eq(1))).thenReturn(new ArrayList<>());

        // generateConfirmOrder 会继续调用 integrationConsumeSettingMapper 等未 mock 依赖
        // 这些在未 mock 时会产生 NPE——这是 Mock 测试的局限性展示：
        // 要完整 mock 9+ 依赖才能测试完整路径。
        // 此处测试"早期依赖的交互是否正确"。

