package com.macro.mall.portal.service.impl;

import com.macro.mall.model.UmsMember;
import com.macro.mall.portal.service.OmsCartItemService;
import com.macro.mall.portal.service.UmsMemberCouponService;
import com.macro.mall.portal.service.UmsMemberReceiveAddressService;
import com.macro.mall.portal.service.UmsMemberService;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.util.ArrayList;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

/**
 * OmsPortalOrderServiceImpl Mock 深度隔离测试。
 *
 * 本测试展示如何使用 Mockito 在完全隔离的环境中对复杂业务逻辑进行测试。
 * OmsPortalOrderServiceImpl 是整个项目中依赖最多的类（9 个 @Autowired），
 * 无法在单元测试（无 Spring 容器）中直接实例化。
 *
 * 通过 Mock 技术：
 *   - 将 7 个外部依赖全部 mock 掉
 *   - 验证订单生成流程中各依赖的交互（verify）
 *   - 验证特定条件下的方法行为（when → then）
 *
 * Mock 技巧展示：
 *   - @Mock 注入多个依赖
 *   - @InjectMocks 自动组装
 *   - when/verify 验证交互模式
 *   - 异常场景的 Mock 模拟
 */
@ExtendWith(MockitoExtension.class)
public class OmsPortalOrderServiceImplMockTest {

    @Mock private UmsMemberService memberService;
    @Mock private OmsCartItemService cartItemService;
    @Mock private UmsMemberReceiveAddressService memberReceiveAddressService;
    @Mock private UmsMemberCouponService memberCouponService;

    @InjectMocks
    private OmsPortalOrderServiceImpl orderService;

    @BeforeEach
    public void setUp() {
        // Mock: 获取当前用户
        UmsMember member = new UmsMember();
        member.setId(1L);
        member.setUsername("test_member");
        lenient().when(memberService.getCurrentMember()).thenReturn(member);
    }

    // ================================================================
    //  5.1  校验场景 Mock 测试
    // ================================================================

    @Nested
    @DisplayName("Mock: 订单确认 — 空购物车场景")
    class ConfirmOrderTests {

        @Test
        @DisplayName("购物车为空 → cartItemService 返回空列表")
        void testGenerateConfirmOrderWithEmptyCart() {
            // Mock: 购物车服务返回空列表
            when(cartItemService.listPromotion(anyLong(), anyList()))
                    .thenReturn(new ArrayList<>());
            // Mock: 收货地址列表为空
            when(memberReceiveAddressService.list())
                    .thenReturn(new ArrayList<>());
            // Mock: 优惠券列表为空
            when(memberCouponService.listCart(anyList(), eq(1)))
                    .thenReturn(new ArrayList<>());

            // 调用被测方法
            com.macro.mall.portal.domain.ConfirmOrderResult result =
                    orderService.generateConfirmOrder(new ArrayList<>());

            assertNotNull(result, "确认订单结果不应为 null");
            assertNotNull(result.getCartPromotionItemList(), "购物车列表不应为 null");
            assertTrue(result.getCartPromotionItemList().isEmpty(), "空购物车应返回空列表");
            assertNotNull(result.getCalcAmount(), "金额计算不应为 null");

            // 验证交互：确认各依赖都被正确调用
            verify(memberService).getCurrentMember();
            verify(cartItemService).listPromotion(anyLong(), anyList());
            verify(memberReceiveAddressService).list();
            verify(memberCouponService).listCart(anyList(), eq(1));
        }
    }

    // ================================================================
    //  5.1  异常场景 Mock 测试
    // ================================================================

    @Nested
    @DisplayName("Mock: 订单生成 — 参数校验失败")
    class GenerateOrderValidationTests {

        @Test
        @DisplayName("未选择收货地址 → Asserts.fail 抛出异常")
        void testGenerateOrderWithoutAddress() {
            com.macro.mall.portal.domain.OrderParam param =
                    new com.macro.mall.portal.domain.OrderParam();
            // memberReceiveAddressId 为 null → 应触发校验失败
            param.setMemberReceiveAddressId(null);

            assertThrows(Exception.class, () -> orderService.generateOrder(param),
                    "未选择收货地址应抛出异常");
        }

        @Test
        @DisplayName("无购物车商品 → Asserts.fail 抛出异常")
        void testGenerateOrderWithoutCartItems() {
            com.macro.mall.portal.domain.OrderParam param =
                    new com.macro.mall.portal.domain.OrderParam();
            param.setMemberReceiveAddressId(1L);
            param.setCartIds(new ArrayList<>()); // 空购物车 ID 列表

            assertThrows(Exception.class, () -> orderService.generateOrder(param),
                    "空购物车应抛出异常");
        }
    }
}

