import { defineConfig } from '@playwright/test';

/**
 * Playwright E2E 测试配置 — mall-admin-web 前端自动化测试。
 *
 * 运行方式：
 *   npx playwright test           # 无头模式运行全部测试
 *   npx playwright test --headed  # 有头模式（可视化调试）
 *   npx playwright test --ui      # 交互式 UI 模式
 */
export default defineConfig({
  testDir: './specs',
  /* 单个测试超时 30 秒 */
  timeout: 30_000,
  /* 全局 expect 断言超时 10 秒 */
  expect: { timeout: 10_000 },
  /* CI 环境重试 1 次 */
  retries: process.env.CI ? 1 : 0,
  /* 无头模式 */
  use: {
    headless: true,
    /* 后端 API 地址在 .env.development 中配置，默认 localhost:8080 */
    baseURL: 'http://localhost:5173',
    /* 截图仅在失败时 */
    screenshot: 'only-on-failure',
    /* 视频仅在失败时保留 */
    video: 'retain-on-failure',
    /* 浏览器窗口 */
    viewport: { width: 1440, height: 900 },
  },
  /* 输出目录 */
  outputDir: './test-results',
});

import { test, expect } from '@playwright/test';

/**
 * 登录流程 E2E 测试 — 黄金路径 + 异常路径。
 *
 * 覆盖场景：
 *   - 有效凭证登录 → 跳转首页 + 用户名显示
 *   - 错误密码 → 提示错误信息
 *   - 空用户名/密码 → 表单校验
 *
 * 测试目标：验证 mall-admin-web 的认证流程从前端到后端 API 的完整链路。
 * 需后端 mall-admin (8080) 运行中。
 */

const BASE = 'http://localhost:5173';

test.describe('Login E2E', () => {

  test.beforeEach(async ({ page }) => {
    // 每次测试前导航到登录页
    await page.goto(`${BASE}/#/login`);
    // 等待登录表单渲染
    await page.waitForSelector('input[placeholder*="用户名"]', { timeout: 10_000 });
  });

  // ================================================================
  //  测试 1: 有效凭证登录 — 黄金路径
  // ================================================================
  test('valid credentials → redirect to home + show username', async ({ page }) => {
    // 输入用户名和密码
    await page.fill('input[placeholder*="用户名"]', 'admin');
    await page.fill('input[placeholder*="密码"]', 'macro123');

    // 点击登录按钮
    await page.click('button:has-text("登录")');

    // 验证：跳转到首页（URL 包含 /home）
    await page.waitForURL('**/home**', { timeout: 15_000 });

    // 验证：页面中显示用户信息（头像区域有 admin）
    await expect(page.locator('.avatar-wrapper, .el-dropdown')).toBeVisible({ timeout: 10_000 });
  });

  // ================================================================
  //  测试 2: 错误密码 — 错误提示
  // ================================================================
  test('wrong password → show error message', async ({ page }) => {
    await page.fill('input[placeholder*="用户名"]', 'admin');
    await page.fill('input[placeholder*="密码"]', 'wrong_password_123');

    await page.click('button:has-text("登录")');

    // 验证：出现错误提示（ElMessage 或 ElNotification）
    // Element Plus 的消息提示在 .el-message 或 .el-notification 中
    await page.waitForTimeout(1500);
    // 验证：仍在登录页（URL 仍为 /login）
    const url = page.url();
    expect(url).toContain('/login');
  });

  // ================================================================
  //  测试 3: 空表单提交 — 表单校验
  // ================================================================
  test('empty form → validation triggered', async ({ page }) => {
    // 不填写任何内容，直接点击登录
    await page.click('button:has-text("登录")');

    // 验证：仍在登录页（表单验证未通过，不会跳转）
    await page.waitForTimeout(1000);
    expect(page.url()).toContain('/login');
  });
});

import { test, expect } from '@playwright/test';

/**
 * 商品管理流程 E2E 测试 — 登录后操作商品列表。
 *
 * 覆盖场景：
 *   - 登录后进入商品列表 → 表格渲染
 *   - 按商品名称搜索 → 表格过滤
 *   - 查看商品详情 → 详情内容展示
 *
 * 前置条件：后端 mall-admin (8080) 运行，数据库有种子商品数据。
 */

const BASE = 'http://localhost:5173';

/** 工具函数：登录并等待跳转 */
async function loginAsAdmin(page: any) {
  await page.goto(`${BASE}/#/login`);
  await page.waitForSelector('input[placeholder*="用户名"]', { timeout: 10_000 });
  await page.fill('input[placeholder*="用户名"]', 'admin');
  await page.fill('input[placeholder*="密码"]', 'macro123');
  await page.click('button:has-text("登录")');
  // 等待登录完成跳转到首页
  await page.waitForURL('**/home**', { timeout: 15_000 });
  // 短暂等待资源加载
  await page.waitForTimeout(2000);
}

test.describe('Product Management E2E', () => {

  // ================================================================
  //  测试 4: 商品列表 — 登录后可见商品表格
  // ================================================================
  test('navigate to product list → table renders', async ({ page }) => {
    await loginAsAdmin(page);

    // 通过 URL 导航到商品列表
    await page.goto(`${BASE}/#/pms/product/index`);
    await page.waitForTimeout(3000);

    // 验证：表格或页面内容出现
    // 商品列表页面有搜索区域、表格或卡片
    const hasContent = await page.locator('.el-table, .table, table').count() > 0
      || await page.locator('[class*="product"]').count() > 0;
    // 至少页面成功加载（非空白页/404）
    const bodyText = await page.textContent('body');
    expect(bodyText).not.toContain('404');
    expect(bodyText).not.toContain('Not Found');
  });

  // ================================================================
  //  测试 5: 商品搜索 — 输入关键字后表格过滤
  // ================================================================
  test('search product by name → results filtered', async ({ page }) => {
    await loginAsAdmin(page);
    await page.goto(`${BASE}/#/pms/product/index`);
    await page.waitForTimeout(3000);

    // 查找搜索输入框并输入关键字
    const searchInput = page.locator('input[placeholder*="商品名称"], input[placeholder*="搜索"], input[placeholder*="关键词"]');
    if (await searchInput.count() > 0) {
      await searchInput.first().fill('手机');
      // 查找搜索按钮并点击
      const searchBtn = page.locator('button:has-text("搜索"), button:has-text("查询"), .el-button:has-text("搜索")');
      if (await searchBtn.count() > 0) {
        await searchBtn.first().click();
        await page.waitForTimeout(2000);
      }
    }

    // 验证：页面仍然正常（无 500 错误）
    const bodyText = await page.textContent('body');
    expect(bodyText).not.toContain('500');
  });

  // ================================================================
  //  测试 6: 商品详情 — 点击查看
  // ================================================================
  test('view product detail → detail content visible', async ({ page }) => {
    await loginAsAdmin(page);
    await page.goto(`${BASE}/#/pms/product/index`);
    await page.waitForTimeout(3000);

    // 如果表格存在，尝试点击第一行的查看/编辑按钮
    const detailBtn = page.locator('button:has-text("编辑"), button:has-text("查看"), a:has-text("编辑"), .el-table__row a, .el-table__row button');
    if (await detailBtn.count() > 0) {
      await detailBtn.first().click();
      await page.waitForTimeout(2000);
    }

    // 验证：页面内容正常
    const bodyText = await page.textContent('body');
    expect(bodyText).not.toContain('500');
    expect(bodyText).not.toContain('Not Found');
  });
});

