      if (await searchBtn.count() > 0) {
        await searchBtn.first().click();
        await page.waitForTimeout(2000);
      }
    }

    // 验证：页面仍然正常（无 500 错误）
    const bodyText = await page.textContent('body');
    expect(bodyText).not.toContain('500');
